#include <bits/stdc++.h>
using namespace std;
typedef double dd;
dd a,b,c,d;
dd fun(dd x)
{
    return a*pow(x,3)+b*pow(x,2)+c*x+d;
}
int main()
{
    dd l,r,mid,point1,point2;
    int num=0;
    cin>>a>>b>>c>>d;
    for(int i=-100;i<100;i++)
    {
        l=i;
        r=i+1;
        point1=fun(l);
        point2=fun(r);
        if(!point1)
        {
            printf("%.2lf ",l);
            num++;
        }
        if(point1*point2<0)
        {
            while(r-l>=0.0001)
            {
                mid=(l+r)/2;
                if(fun(mid)*fun(r)>0)
                {
                    r=mid;
                }
                else{
                    l=mid;
                }
            }
            printf("%.2lf ",r);
            num++;
        }
        if(num==3)
        {
            break;
        }
    }
    return 0;
}
